                                <h2 id="dashboard-administrative-officer-command-center-GETapi-dashboard-metrics">Get comprehensive dashboard metrics</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Retrieve all dashboard metrics in a single call including expiring budgets,
critical stock items, and employees due for step increment.</p>

<span id="example-requests-GETapi-dashboard-metrics">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost:8000/api/dashboard/metrics?budget_days=60&amp;stock_prediction_days=14&amp;stock_usage_window=30&amp;step_increment_days=60&amp;step_increment_months=36" \
    --header "Authorization: Bearer {YOUR_SANCTUM_TOKEN}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/dashboard/metrics"
);

const params = {
    "budget_days": "60",
    "stock_prediction_days": "14",
    "stock_usage_window": "30",
    "step_increment_days": "60",
    "step_increment_months": "36",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer {YOUR_SANCTUM_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>

