<span id="example-requests-PUTapi-purchase-requests--id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://localhost:8000/api/purchase-requests/architecto" \
    --header "Authorization: Bearer {YOUR_SANCTUM_TOKEN}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"purpose\": \"architecto\",
    \"fund_source\": \"n\",
    \"pr_date\": \"2026-05-20T08:10:02\",
    \"department\": \"g\",
    \"section\": \"z\",
    \"fund_cluster\": \"m\",
    \"ppmp_reference\": \"i\",
    \"procurement_mode\": \"y\",
    \"estimated_budget\": 60,
    \"total_amount\": 42,
    \"date_needed\": \"2026-05-20T08:10:02\",
    \"delivery_date\": \"2026-05-20T08:10:02\",
    \"delivery_location\": \"l\",
    \"remarks\": \"architecto\",
    \"terms_and_conditions\": \"architecto\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/purchase-requests/architecto"
);

const headers = {
    "Authorization": "Bearer {YOUR_SANCTUM_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "purpose": "architecto",
    "fund_source": "n",
    "pr_date": "2026-05-20T08:10:02",
    "department": "g",
    "section": "z",
    "fund_cluster": "m",
    "ppmp_reference": "i",
    "procurement_mode": "y",
    "estimated_budget": 60,
    "total_amount": 42,
    "date_needed": "2026-05-20T08:10:02",
    "delivery_date": "2026-05-20T08:10:02",
    "delivery_location": "l",
    "remarks": "architecto",
    "terms_and_conditions": "architecto"
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

