                    <h2 id="endpoints-POSTapi-liquidations">POST api/liquidations</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-POSTapi-liquidations">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/liquidations" \
    --header "Authorization: Bearer {YOUR_SANCTUM_TOKEN}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"cash_advance_id\": 16,
    \"liquidation_date\": \"2026-05-20T08:10:05\",
    \"total_expenses\": 39,
    \"liquidation_number\": \"g\",
    \"supporting_documents\": \"architecto\",
    \"summary_of_expenses\": \"architecto\",
    \"amount_to_refund\": 39,
    \"additional_cash_needed\": 84,
    \"remarks\": \"architecto\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/liquidations"
);

const headers = {
    "Authorization": "Bearer {YOUR_SANCTUM_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "cash_advance_id": 16,
    "liquidation_date": "2026-05-20T08:10:05",
    "total_expenses": 39,
    "liquidation_number": "g",
    "supporting_documents": "architecto",
    "summary_of_expenses": "architecto",
    "amount_to_refund": 39,
    "additional_cash_needed": 84,
    "remarks": "architecto"
};

fetch(url, {
