                    <h2 id="endpoints-POSTapi-documents-upload">POST api/documents/upload</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-POSTapi-documents-upload">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/documents/upload" \
    --header "Authorization: Bearer {YOUR_SANCTUM_TOKEN}" \
    --header "Content-Type: multipart/form-data" \
    --header "Accept: application/json" \
    --form "documentable_type=PurchaseRequest"\
    --form "documentable_id=16"\
    --form "document_type=delivery_receipt"\
    --form "description=Et animi quos velit et fugiat."\
    --form "file=@C:\Users\252164.JEnrique\AppData\Local\Temp\php2A99.tmp" </code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/documents/upload"
);

const headers = {
    "Authorization": "Bearer {YOUR_SANCTUM_TOKEN}",
    "Content-Type": "multipart/form-data",
    "Accept": "application/json",
};

const body = new FormData();
body.append('documentable_type', 'PurchaseRequest');
body.append('documentable_id', '16');
body.append('document_type', 'delivery_receipt');
body.append('description', 'Et animi quos velit et fugiat.');
body.append('file', document.querySelector('input[name="file"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>

