                    <h2 id="hr-management-employees-PUTapi-employees--id-">Update employee</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Update an existing employee's information.</p>

<span id="example-requests-PUTapi-employees--id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://localhost:8000/api/employees/1" \
    --header "Authorization: Bearer {YOUR_SANCTUM_TOKEN}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"first_name\": \"b\",
    \"middle_name\": \"n\",
    \"last_name\": \"g\",
    \"suffix\": \"zmiyvd\",
    \"date_of_birth\": \"2022-06-13\",
    \"gender\": \"Female\",
    \"civil_status\": \"Separated\",
    \"email\": \"zbailey@example.net\",
    \"mobile_number\": \"iyvdljnikhwaykcm\",
    \"address\": \"architecto\",
    \"city\": \"n\",
    \"province\": \"g\",
    \"zip_code\": \"zmiyvd\",
    \"plantilla_item_no\": \"l\",
    \"position\": \"j\",
    \"position_title\": \"n\",
    \"salary_grade\": 5,
    \"step_increment\": 7,
    \"monthly_salary\": 7,
    \"employment_status\": \"Temporary\",
    \"date_hired\": \"2026-05-20T08:10:02\",
    \"date_separated\": \"2052-06-12\",
    \"tin\": \"ngzmiyvdljnikhwa\",
    \"gsis_number\": \"ykcmyuwpwlvqwrsi\",
    \"philhealth_number\": \"tcpscqldzsnrwtuj\",
    \"pagibig_number\": \"wvlxjklqppwqbewt\",
    \"sss_number\": \"nnoqitpxntltcvip\",
    \"vacation_leave_credits\": 1,
    \"sick_leave_credits\": 87,
    \"status\": \"Retired\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/employees/1"
);

const headers = {
    "Authorization": "Bearer {YOUR_SANCTUM_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "first_name": "b",
    "middle_name": "n",
    "last_name": "g",
    "suffix": "zmiyvd",
    "date_of_birth": "2022-06-13",
    "gender": "Female",
    "civil_status": "Separated",
    "email": "zbailey@example.net",
    "mobile_number": "iyvdljnikhwaykcm",
    "address": "architecto",
    "city": "n",
    "province": "g",
    "zip_code": "zmiyvd",
    "plantilla_item_no": "l",
    "position": "j",
    "position_title": "n",
    "salary_grade": 5,
    "step_increment": 7,
    "monthly_salary": 7,
    "employment_status": "Temporary",
    "date_hired": "2026-05-20T08:10:02",
    "date_separated": "2052-06-12",
    "tin": "ngzmiyvdljnikhwa",
    "gsis_number": "ykcmyuwpwlvqwrsi",
    "philhealth_number": "tcpscqldzsnrwtuj",
    "pagibig_number": "wvlxjklqppwqbewt",
    "sss_number": "nnoqitpxntltcvip",
    "vacation_leave_credits": 1,
    "sick_leave_credits": 87,
    "status": "Retired"
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

