                    <h2 id="hr-management-leave-requests-POSTapi-leave-requests">Create leave request</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Create a new leave request with automatic leave credit validation.</p>

<span id="example-requests-POSTapi-leave-requests">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/leave-requests" \
    --header "Authorization: Bearer {YOUR_SANCTUM_TOKEN}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"employee_id\": 1,
    \"leave_type\": \"Vacation Leave\",
    \"start_date\": \"2024-07-01\",
    \"end_date\": \"2024-07-05\",
    \"days_requested\": 39,
    \"sick_leave_type\": \"Out Patient\",
    \"illness\": \"g\",
    \"reason\": \"Family vacation\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/leave-requests"
);

const headers = {
    "Authorization": "Bearer {YOUR_SANCTUM_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "employee_id": 1,
    "leave_type": "Vacation Leave",
    "start_date": "2024-07-01",
    "end_date": "2024-07-05",
    "days_requested": 39,
    "sick_leave_type": "Out Patient",
    "illness": "g",
    "reason": "Family vacation"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

