                    <h2 id="hr-management-service-records-PUTapi-service-records--id-">Update service record</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-PUTapi-service-records--id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://localhost:8000/api/service-records/1" \
    --header "Authorization: Bearer {YOUR_SANCTUM_TOKEN}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"employee_id\": 16,
    \"date_from\": \"2026-05-20T08:10:02\",
    \"date_to\": \"2052-06-12\",
    \"designation\": \"n\",
    \"status_of_appointment\": \"Contractual\",
    \"salary_grade\": 7,
    \"step_increment\": 6,
    \"monthly_salary\": 77,
    \"station_place_of_assignment\": \"i\",
    \"office_entity\": \"y\",
    \"government_service\": \"Yes\",
    \"action_type\": \"Demotion\",
    \"appointment_authority\": \"v\",
    \"appointment_date\": \"2026-05-20T08:10:02\",
    \"remarks\": \"d\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/service-records/1"
);

const headers = {
    "Authorization": "Bearer {YOUR_SANCTUM_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "employee_id": 16,
    "date_from": "2026-05-20T08:10:02",
    "date_to": "2052-06-12",
    "designation": "n",
    "status_of_appointment": "Contractual",
    "salary_grade": 7,
    "step_increment": 6,
    "monthly_salary": 77,
    "station_place_of_assignment": "i",
    "office_entity": "y",
    "government_service": "Yes",
    "action_type": "Demotion",
    "appointment_authority": "v",
    "appointment_date": "2026-05-20T08:10:02",
    "remarks": "d"
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

